  1	/* eslint-disable @typescript-eslint/no-explicit-any */
  2	import {
  3	  Button,
  4	  PageSection,
  5	  Title,
  6	  Wizard,
  7	  WizardFooterWrapper,
  8	  WizardStep,
  9	  WizardStepType
 10	} from '@patternfly/react-core';
 11	import { RJSFSchema } from '@rjsf/utils';
 12	import validator from '@rjsf/validator-ajv8';
 13	import _ from 'lodash';
 14	import React, { FC } from 'react';
 15	import { useTranslation } from 'react-i18next';
 16	import {
 17	  flowCollectorEditPath,
 18	  flowCollectorNewPath,
 19	  flowCollectorStatusPath,
 20	  navigateTo,
 21	  useNavigate,
 22	  useParams
 23	} from '../../utils/url';
 24	import { flowCollectorUISchema } from './config/uiSchema';
 25	import Consumption from './consumption';
 26	import { DynamicForm } from './dynamic-form/dynamic-form';
 27	import { ErrorTemplate } from './dynamic-form/templates';
 28	import './forms.css';
 29	import ResourceWatcher, { Consumer } from './resource-watcher';
 30	import { getFilteredUISchema } from './utils';
 31	
 32	export type FlowCollectorWizardProps = {
 33	  name?: string;
 34	};
 35	
 36	const defaultPaths = ['spec.namespace', 'spec.networkPolicy'];
 37	
 38	export const FlowCollectorWizard: FC<FlowCollectorWizardProps> = props => {
 39	  const { t } = useTranslation('plugin__netobserv-plugin');
 40	  const [schema, setSchema] = React.useState<RJSFSchema | null>(null);
 41	  const [data, setData] = React.useState<any>(null);
 42	  const [paths, setPaths] = React.useState<string[]>(defaultPaths);
 43	  const params = useParams<{ name?: string }>();
 44	  const navigate = useNavigate();
 45	
 46	  const form = React.useCallback(
 47	    (errors?: string[]) => {
 48	      if (!schema) {
 49	        return <></>;
 50	      }
 51	      const filteredSchema = getFilteredUISchema(flowCollectorUISchema, paths);
 52	      return (
 53	        <DynamicForm
 54	          formData={data}
 55	          schema={schema}
 56	          uiSchema={filteredSchema} // see if we can regenerate this from CSV
 57	          validator={validator}
 58	          onChange={event => {
 59	            setData(event.formData);
 60	          }}
 61	          errors={errors}
 62	          skipDefaults
 63	        />
 64	      );
 65	    },
 66	    [data, paths, schema]
 67	  );
 68	
 69	  const onStepChange = React.useCallback((_event: React.MouseEvent<HTMLButtonElement>, step: WizardStepType) => {
 70	    switch (step.id) {
 71	      case 'overview':
 72	        setPaths(defaultPaths);
 73	        break;
 74	      case 'processing':
 75	        setPaths([
 76	          'spec.deploymentModel',
 77	          'spec.kafka.address',
 78	          'spec.kafka.topic',
 79	          'spec.kafka.tls',
 80	          'spec.agent.ebpf.privileged',
 81	          'spec.agent.ebpf.features',
 82	          'spec.processor.clusterName',
 83	          'spec.processor.addZone',
 84	          'spec.processor.consumerReplicas'
 85	        ]);
 86	        break;
 87	      case 'loki':
 88	        setPaths(['spec.loki']);
 89	        break;
 90	      default:
 91	        setPaths([]);
 92	    }
 93	  }, []);
 94	
 95	  const setSampling = React.useCallback(
 96	    (sampling: number) => {
 97	      if (!data) {
 98	        return;
 99	      }
100	      data.spec.agent.ebpf.sampling = sampling;
101	      setData({ ...data });
102	    },
103	    [data]
104	  );
105	
106	  return (
107	    <ResourceWatcher
108	      group="flows.netobserv.io"
109	      version="v1beta2"
110	      kind="FlowCollector"
111	      name={params.name || props.name || 'cluster'} // fallback on cluster to ensure it doesn't already exists
112	      skipCRError
113	      onSuccess={() => {
114	        navigate(flowCollectorStatusPath);
115	      }}
116	      defaultFrom="CSVExample"
117	    >
118	      <Consumer>
119	        {ctx => {
120	          // redirect to edit page if resource already exists or is created while using the wizard
121	          // We can't handle edition here since this page doesn't include ResourceYAMLEditor
122	          // which handle reload / update buttons
123	          if (ctx.data.metadata?.resourceVersion) {
124	            navigate(flowCollectorEditPath);
125	          }
126	          // first init schema & data when watch resource query got results
127	          if (schema == null) {
128	            setSchema(ctx.schema);
129	          }
130	          if (data == null) {
131	            // slightly modify default example when creating a new resource
132	            if (params.name !== 'cluster') {
133	              const updatedData = _.cloneDeep(ctx.data) as any;
134	              if (!updatedData.spec) {
135	                updatedData.spec = {};
136	              }
137	              if (!updatedData.spec.loki) {
138	                updatedData.spec.loki = {};
139	              }
140	              updatedData.spec.loki.mode = 'LokiStack'; // default to lokistack
141	              setData(updatedData);
142	            } else {
143	              setData(ctx.data);
144	            }
145	          }
146	          return (
147	            <PageSection id="pageSection">
148	              <div id="pageHeader">
149	                <Title headingLevel="h1" size="2xl">
150	                  {t('Network Observability FlowCollector setup')}
151	                </Title>
152	              </div>
153	              <div id="wizard-container">
154	                <Wizard onStepChange={onStepChange} onSave={() => ctx.onSubmit(data)} onClose={() => navigateTo('/')}>
155	                  <WizardStep name={t('Overview')} id="overview">
156	                    <span className="co-pre-line">
157	                      {t(
158	                        // eslint-disable-next-line max-len
159	                        'The FlowCollector resource is used to configure the Network Observability operator and its managed components. When it is created, network flows start being collected.'
160	                      )}
161	                      <br /> <br />
162	                      {t(
163	                        // eslint-disable-next-line max-len
164	                        'This wizard is a helper to create a first FlowCollector resource. It does not cover all the available configuration options, but only the most common ones.\nFor advanced configuration, please use YAML or the'
165	                      )}{' '}
166	                      <Button
167	                        id="open-flow-collector-form"
168	                        data-test-id="open-flow-collector-form"
169	                        className="no-padding"
170	                        variant="link"
171	                        onClick={() => navigateTo(flowCollectorNewPath)}
172	                      >
173	                        {t('FlowCollector form')}
174	                      </Button>
175	                      {t(
176	                        // eslint-disable-next-line max-len
177	                        ', which includes more options such as:\n- Filtering options\n- Configuring custom exporters\n- Custom labels based on IP\n- Pod identification for secondary networks\n- Performance fine-tuning\nYou can always edit a FlowCollector later when you start with the simplified configuration.'
178	                      )}
179	                      <br /> <br />
180	                      {t('Operator configuration')}
181	                    </span>
182	                    {form(ctx.errors)}
183	                  </WizardStep>
184	                  <WizardStep name={t('Processing')} id="processing">
185	                    {form(ctx.errors)}
186	                  </WizardStep>
187	                  <WizardStep name={t('Loki')} id="loki">
188	                    {form(ctx.errors)}
189	                  </WizardStep>
190	                  <WizardStep
191	                    name={t('Consumption')}
192	                    id="consumption"
193	                    footer={
194	                      <WizardFooterWrapper>
195	                        <Button variant="primary" onClick={() => ctx.onSubmit(data)}>
196	                          {t('Submit')}
197	                        </Button>
198	                        <Button variant="link" onClick={() => navigateTo('/')}>
199	                          {t('Cancel')}
200	                        </Button>
201	                      </WizardFooterWrapper>
202	                    }
203	                  >
204	                    <Consumption flowCollector={data} setSampling={setSampling} />
205	                    <>{!_.isEmpty(ctx.errors) && <ErrorTemplate errors={ctx.errors} />}</>
206	                  </WizardStep>
207	                </Wizard>
208	              </div>
209	            </PageSection>
210	          );
211	        }}
212	      </Consumer>
213	    </ResourceWatcher>
214	  );
215	};
216	
217	export default FlowCollectorWizard;

